+/*
+ * Custom prose styles based on Streamdown's typography
+ * Used for rendering markdown content from react-markdown
+ */
+
+.prose {
+  /* Base text styling */
+  font-size: var(--text-sm);
+  line-height: 1.75;
+  color: var(--color-foreground);
+
+  /* Spacing between elements */
+  > * + * {
+    margin-top: 1rem;
+  }
+
+  /* Remove top margin from first child, bottom margin from last */
+  > :first-child {
+    margin-top: 0;
+  }
+  > :last-child {
+    margin-bottom: 0;
+  }
+
+  /* Headings */
+  h1 {
+    margin-top: 1.5rem;
+    margin-bottom: 0.5rem;
+    font-size: var(--text-3xl);
+    font-weight: var(--font-weight-semibold);
+    line-height: 1.25;
+    color: var(--color-foreground);
+  }
+
+  h2 {
+    margin-top: 1.5rem;
+    margin-bottom: 0.5rem;
+    font-size: var(--text-2xl);
+    font-weight: var(--font-weight-semibold);
+    line-height: 1.3;
+    color: var(--color-foreground);
+  }
+
+  h3 {
+    margin-top: 1.5rem;
+    margin-bottom: 0.5rem;
+    font-size: var(--text-xl);
+    font-weight: var(--font-weight-semibold);
+    line-height: 1.4;
+    color: var(--color-foreground);
+  }
+
+  h4 {
+    margin-top: 1.5rem;
+    margin-bottom: 0.5rem;
+    font-size: var(--text-lg);
+    font-weight: var(--font-weight-semibold);
+    line-height: 1.5;
+    color: var(--color-foreground);
+  }
+
+  h5 {
+    margin-top: 1.5rem;
+    margin-bottom: 0.5rem;
+    font-size: var(--text-base);
+    font-weight: var(--font-weight-semibold);
+    line-height: 1.5;
+    color: var(--color-foreground);
+  }
+
+  h6 {
+    margin-top: 1.5rem;
+    margin-bottom: 0.5rem;
+    font-size: var(--text-sm);
+    font-weight: var(--font-weight-semibold);
+    line-height: 1.5;
+    color: var(--color-foreground);
+  }
+
+  /* Paragraphs */
+  p {
+    margin-top: 1rem;
+    margin-bottom: 1rem;
+  }
+
+  /* Strong/bold */
+  strong {
+    font-weight: var(--font-weight-semibold);
+    color: var(--color-foreground);
+  }
+
+  /* Emphasis/italic */
+  em {
+    font-style: italic;
+  }
+
+  /* Links */
+  a {
+    color: var(--color-primary);
+    font-weight: var(--font-weight-medium);
+    text-decoration: underline;
+    text-underline-offset: 2px;
+    overflow-wrap: anywhere;
+
+    &:hover {
+      opacity: 0.8;
+    }
+  }
+
+  /* Inline code */
+  :not(pre) > code {
+    padding: 0.125rem 0.375rem;
+    border-radius: calc(var(--radius) - 2px);
+    background-color: var(--color-muted);
+    font-family: var(--font-mono);
+    font-size: 0.875em;
+  }
+
+  /* Code blocks */
+  pre {
+    margin-top: 1rem;
+    margin-bottom: 1rem;
+    padding: 1rem;
+    overflow-x: auto;
+    border-radius: var(--radius);
+    border: 1px solid var(--color-border);
+    background-color: oklch(0.205 0 0); /* --card in dark mode */
+    font-family: var(--font-mono);
+    font-size: var(--text-sm);
+    line-height: 1.75;
+
+    code {
+      padding: 0;
+      border-radius: 0;
+      background-color: transparent;
+      font-size: inherit;
+    }
+  }
+
+  /* Blockquotes */
+  blockquote {
+    margin-top: 1rem;
+    margin-bottom: 1rem;
+    padding-left: 1rem;
+    border-left: 4px solid var(--color-muted-foreground/30);
+    color: var(--color-muted-foreground);
+    font-style: italic;
+
+    p {
+      margin-top: 0.5rem;
+      margin-bottom: 0.5rem;
+    }
+  }
+
+  /* Horizontal rules */
+  hr {
+    margin-top: 1.5rem;
+    margin-bottom: 1.5rem;
+    border-color: var(--color-border);
+  }
+
+  /* Ordered lists */
+  ol {
+    margin-top: 1rem;
+    margin-bottom: 1rem;
+    padding-left: 1.5rem;
+    list-style-type: decimal;
+    list-style-position: inside;
+  }
+
+  /* Unordered lists */
+  ul {
+    margin-top: 1rem;
+    margin-bottom: 1rem;
+    padding-left: 1.5rem;
+    list-style-type: disc;
+    list-style-position: inside;
+  }
+
+  /* Nested lists */
+  li > ol,
+  li > ul {
+    margin-top: 0.25rem;
+    margin-bottom: 0.25rem;
+    padding-left: 1.5rem;
+  }
+
+  /* List items */
+  li {
+    padding-top: 0.25rem;
+    padding-bottom: 0.25rem;
+
+    /* Inline paragraphs in list items */
+    > p {
+      display: inline;
+    }
+  }
+
+  li + li {
+    margin-top: 0.25rem;
+  }
+
+  /* Tables */
+  table {
+    width: 100%;
+    margin-top: 1rem;
+    margin-bottom: 1rem;
+    border-collapse: separate;
+    border-spacing: 0;
+    border: 1px solid var(--color-border);
+    border-radius: var(--radius);
+    overflow: hidden;
+    font-size: var(--text-sm);
+  }
+
+  thead {
+    background-color: var(--color-muted/80);
+  }
+
+  tbody {
+    background-color: var(--color-muted/40);
+  }
+
+  tr {
+    border-bottom: 1px solid var(--color-border);
+  }
+
+  /* Remove bottom border from last row */
+  tbody tr:last-child {
+    border-bottom: none;
+  }
+
+  th,
+  td {
+    padding: 0.5rem 1rem;
+    border-bottom: 1px solid var(--color-border);
+  }
+
+  /* Remove bottom border from last row cells */
+  tbody tr:last-child th,
+  tbody tr:last-child td {
+    border-bottom: none;
+  }
+
+  th {
+    text-align: left;
+    font-weight: var(--font-weight-semibold);
+    white-space: nowrap;
+  }
+
+  /* Images */
+  img {
+    max-width: 100%;
+    height: auto;
+    margin-top: 1rem;
+    margin-bottom: 1rem;
+    border-radius: var(--radius);
+  }
+
+  /* Task lists (GFM) */
+  input[type="checkbox"] {
+    margin-right: 0.5rem;
+  }
+
+  /* Strikethrough */
+  del {
+    text-decoration: line-through;
+    opacity: 0.7;
+  }
+}
+
+/* Smaller prose variant */
+.prose-sm {
+  font-size: var(--text-sm);
+
+  h1 {
+    font-size: var(--text-2xl);
+  }
+  h2 {
+    font-size: var(--text-xl);
+  }
+  h3 {
+    font-size: var(--text-lg);
+  }
+  h4 {
+    font-size: var(--text-base);
+  }
+  h5,
+  h6 {
+    font-size: var(--text-sm);
+  }
+}
+
+/* Dark/inverted prose (for dark backgrounds) */
+.prose-invert {
+  color: var(--color-foreground);
+
+  a {
+    color: var(--color-primary);
+  }
+
+  :not(pre) > code {
+    background-color: var(--color-muted);
+  }
+
+  pre {
+    background-color: oklch(0.145 0 0); /* slightly darker than card */
+    border-color: var(--color-border);
+  }
+
+  blockquote {
+    border-color: var(--color-muted-foreground/30);
+    color: var(--color-muted-foreground);
+  }
+}
